const express = require('express');
const logger = require('./logger'); // assuming a custom logger module
const apiKeys = require('./api-keys.json'); // assuming an API keys configuration file

const app = express();

// Set up API key validation and forwarding middleware
function apiKeyMiddleware(req, res, next) {
  const apiKey = req.query.api_key;
  if (!apiKey || !apiKeys.includes(apiKey)) {
    return res.status(401).send('Invalid API key');
  }
  req.headers['x-api-key'] = apiKey;
  next();
}

// Set up logging middleware
function logRequest(req, res, next) {
  const apikey = req.headers['x-api-key'];
  logger.info(`Received request to ${req.originalUrl} with API key: ${apikey}`);
  next();
}

// Set up route forwarding
app.use(logRequest);
app.use(apiKeyMiddleware);

const backendServices = {
  '/users': 'http://localhost:3001/users',
  '/products': 'http://localhost:3002/products'
};

Object.keys(backendServices).forEach(route => {
  app.all(route, (req, res) => {
    const targetUrl = backendServices[route];
    req.pipe(request(targetUrl)).pipe(res);
  });
});

// Start the server
const port = process.env.PORT || 3000;
app.listen(port, () => {
  logger.info(`API gateway listening on port ${port}`);
});